-- PARTE 5/6 — conteúdo das iscas 19–24
update public.blog_templum_iscas set headline='IA na empresa, <em>casos</em><br>práticos, não <em>promessas</em>.', subhead='Empresa que adota IA seguindo hype gasta dinheiro e fica frustrada. Esse guia mostra onde IA gera retorno real em gestão, processo e atendimento.', benefits='["Onde IA <strong>já entrega resultado</strong> em PMEs.","Casos reais de <strong>uso em gestão</strong>.","Como começar com <strong>baixo investimento</strong>.","Como evitar virar <strong>refém de fornecedor</strong>."]'::jsonb, steps='[{"num":"01","title":"O que IA é hoje","text":"Diferença entre IA, automação e RPA, sem hype."},{"num":"02","title":"Onde aplicar primeiro","text":"Casos onde retorno aparece em 90 dias."},{"num":"03","title":"Atendimento","text":"Como IA melhora suporte sem perder qualidade humana."},{"num":"04","title":"Gestão","text":"Análise de dados, indicadores e antecipação de problemas."},{"num":"05","title":"Implementação","text":"Roteiro de adoção com baixo risco e investimento controlado."},{"num":"06","title":"Riscos","text":"Privacidade, dependência de fornecedor e governança."}]'::jsonb, cta_title='IA não substitui <em>gestão</em>.<br>Boa gestão <em>amplificada</em>.', cta_copy='Esse guia foi escrito pra empresário e gestor, não pra cientista de dados. Linguagem clara, casos reais.', cta_items='["Casos por porte e setor","Roteiro de implementação","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='inteligencia-artificial-como-transformar-sua-empresa-com-ia-na-pratica';
update public.blog_templum_iscas set headline='Gestão de riscos,<br>de planilha <em>solta</em><br>a processo <em>vivo</em>.', subhead='Planilha estruturada para identificar riscos por processo, avaliar com critérios claros e gerar plano de ação com responsável e prazo.', benefits='["<strong>Identificação por processo</strong>, não por chute geral.","Matriz <strong>probabilidade × impacto</strong> com cálculo automático.","<strong>Plano de ação</strong> com responsável, prazo e evidência.","Pronta para apresentar em <strong>análise crítica</strong>."]'::jsonb, steps='[{"num":"01","title":"Identificação","text":"Aba para listar riscos e oportunidades por processo ou área."},{"num":"02","title":"Avaliação","text":"Matriz com probabilidade e impacto, com cálculo automático de prioridade."},{"num":"03","title":"Tratamento","text":"Escolha do tratamento (evitar, mitigar, transferir, aceitar) com plano."},{"num":"04","title":"Monitoramento","text":"Acompanhamento de status, eficácia e reavaliação periódica."}]'::jsonb, cta_title='Risco sem matriz<br>é só <em>opinião</em>.', cta_copy='A planilha te dá estrutura imediata, sem precisar montar fórmula nenhuma. Copia, preenche e usa.', cta_items='["Compatível com Google Sheets e Excel","Pronta para auditoria ISO 9001","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-riscos-e-oportunidades';
update public.blog_templum_iscas set headline='Plano operacional que<br>conecta <em>estratégia</em><br>e <em>execução</em>.', subhead='Da meta da diretoria à ação do time, sem perder ninguém pelo caminho. Planilha pronta com cascateamento de objetivos e gestão de marcos.', benefits='["<strong>Cascateamento</strong> de meta estratégica em ação operacional.","<strong>Marcos</strong> com prazo e responsável.","Acompanhamento de <strong>status semanal</strong>.","Visão de <strong>gargalo</strong> antes do prazo estourar."]'::jsonb, steps='[{"num":"01","title":"Metas estratégicas","text":"Aba para registrar os objetivos macro da empresa."},{"num":"02","title":"Desdobramento","text":"Cascateamento até ação operacional, quem faz o quê e quando."},{"num":"03","title":"Marcos","text":"Linha do tempo com checkpoints visíveis."},{"num":"04","title":"Status e farol","text":"Acompanhamento semanal com sinalização de risco."}]'::jsonb, cta_title='Plano que <em>vive</em>.<br>Não plano que <em>enfeita</em>.', cta_copy='Planilha pronta com fórmulas e validações, você abre e começa a usar.', cta_items='["Cascateamento até nível de tarefa","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-plano-operacional';
update public.blog_templum_iscas set headline='Mudança controlada,<br>auditoria <em>tranquila</em>.', subhead='Toda norma exige gestão de mudança, e auditor sempre puxa. Planilha estruturada para registrar, avaliar impacto, aprovar e implementar mudanças.', benefits='["Registro com <strong>análise de impacto</strong> antes da implementação.","<strong>Aprovação</strong> formal com trilha visível.","<strong>Comunicação</strong> a partes interessadas.","Verificação de <strong>eficácia</strong> pós-implementação."]'::jsonb, steps='[{"num":"01","title":"Registro","text":"Identificação da mudança, motivo e processo impactado."},{"num":"02","title":"Análise de impacto","text":"Avaliação de riscos, recursos e partes interessadas."},{"num":"03","title":"Aprovação","text":"Trilha de aprovação formal com responsáveis."},{"num":"04","title":"Verificação","text":"Acompanhamento pós-implementação e evidência de eficácia."}]'::jsonb, cta_title='Auditor pergunta,<br>você <em>mostra</em>.', cta_copy='Planilha que vira evidência direta na auditoria. Estrutura e fórmulas já prontas.', cta_items='["Aderente a ISO 9001, 14001 e 45001","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-controle-de-mudanca';
update public.blog_templum_iscas set headline='RNC que <em>fecha o ciclo</em>,<br>não que enche <em>arquivo</em>.', subhead='Planilha completa de relatório de não conformidade: registro, análise de causa raiz, ação corretiva, verificação e fechamento.', benefits='["Registro com <strong>contenção imediata</strong> e descrição clara.","<strong>Análise de causa raiz</strong> com 5 Porquês.","<strong>Ação corretiva</strong> com responsável e prazo.","<strong>Verificação de eficácia</strong> antes de fechar."]'::jsonb, steps='[{"num":"01","title":"Registro","text":"Descrição da NC, contenção imediata e classificação."},{"num":"02","title":"Causa raiz","text":"Análise estruturada com 5 Porquês ou Ishikawa."},{"num":"03","title":"Ação corretiva","text":"Plano com responsável, prazo e recursos."},{"num":"04","title":"Verificação","text":"Comprovação de eficácia antes do fechamento da NC."}]'::jsonb, cta_title='NC bem tratada<br><em>não volta</em>.', cta_copy='Planilha estruturada para sair do ciclo "tampa-buraco" e gerar tratamento real de causa.', cta_items='["Aderente a ISO 9001, 14001 e 45001","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-relatorio-de-nao-conformidade';
update public.blog_templum_iscas set headline='SGI <em>integrado</em><br>em uma planilha só.', subhead='Sistema de Gestão Integrado em planilha estruturada: processos, partes interessadas, riscos, controles e indicadores conectados.', benefits='["Mapa de <strong>processos</strong> conectado a riscos e indicadores.","<strong>Partes interessadas</strong> e suas exigências.","Controles <strong>cruzados</strong> entre ISO 9001, 14001 e 45001.","<strong>Indicadores</strong> ligados aos objetivos do SGI."]'::jsonb, steps='[{"num":"01","title":"Processos","text":"Cadeia de valor com processos primários, de apoio e gerenciais."},{"num":"02","title":"Partes interessadas","text":"Stakeholders e suas expectativas mapeados por processo."},{"num":"03","title":"Riscos e oportunidades","text":"Avaliação cruzada para qualidade, ambiental e SST."},{"num":"04","title":"Indicadores","text":"Métricas que falam com os três sistemas em paralelo."}]'::jsonb, cta_title='Integração de verdade<br>começa no <em>mapa</em>.', cta_copy='Empresas com SGI gastam metade do tempo em manutenção quando os sistemas estão conectados. A planilha mostra como.', cta_items='["Estrutura cruzada ISO 9001/14001/45001","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-mapeamento-sgi';
